var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"이...... 이건......!","JPN":"こ、これは……！","ENG":"Wait... Impossible!","TWN":"這……這是……！"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"왕께서 내린 계시에 너 같은 존재는 없었다......!","JPN":"王の啓示に貴様のような奴はいなかった……！","ENG":"There was no being like you in the Queen's prophecy!","TWN":"王所下達的啟示裡沒有妳這樣的存在……！"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"너는...... 너는 대체 무엇이냐?!","JPN":"貴様は……貴様は一体何者だ！？","ENG":"You... What are you?!","TWN":"妳……妳到底是什麼東西？！"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"너 같은 놈들은 항상 말이 많군.","JPN":"お前のような奴らは本当によく喋るな。","ENG":"Bad guys like you always talk too much.","TWN":"你們總是這麼囉嗦。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"난 말이지...... 구 관리국 시절부터 나보다 약한 녀석과 싸워 본 적이 한 번도 없어.","JPN":"私は……旧管理局時代から、自分より弱い奴と戦ったことはない。","ENG":"You see... I've never fought anyone weaker than me since the Old Administration.","TWN":"我啊……從舊管理局時期開始，就從來沒有和比我弱的敵人戰鬥過。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"싸우면서 내 CRF 등급이 어떠니, 상대가 몇 종 침식체니 하는 걸 따지는 얼간이는 절대로 늑대의 문장을 달 수가 없으니까.","JPN":"私のCRFランクや、相手の侵食体の種類がどうのこうのと\\nうるさい間抜けは、決してオオカミの紋章を継ぐことができないだろうから。","ENG":"Fools who weigh their CRF grades or C.O.s' categories during the fight can never wear the Seal of the Wolf.","TWN":"一邊戰鬥，一邊問別人的CRF等級多少、對方是幾類侵蝕體，像這樣的傻子是不配戴上狼之紋章的。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"늑대의 문장이라고......?","JPN":"オオカミの紋章だと……？","ENG":"Seal of the Wolf?","TWN":"狼之紋章……？"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"설마, 펜릴......!","JPN":"まさか、フェンリル……！","ENG":"No, Fenrir?!","TWN":"妳該不會是，芬里爾……！"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"잡설이 길었군. 이만 꺼져라.","JPN":"話が長くなったな。もう消えろ。","ENG":"Enough small talk. Now get lost.","TWN":"廢話太多了，消失吧。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"아아아아아아아아!!","JPN":"ぐあああああぁ！！","ENG":"Aaaah!!","TWN":"啊啊啊啊啊啊！！"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"후우......","JPN":"ふう……","ENG":"Phew...","TWN":"呼……"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"이 정도로 지치다니, 나도 예전 같진 않네.","JPN":"この程度で疲れるなんて、昔のようにはいかないみたい。","ENG":"I'm all worn out after that? I guess it's not like the good old days anymore.","TWN":"才這種程度就精疲力盡了，看來我也不如從前了。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"하지만 이 전투복, 옛날 생각이 나게 하는걸.","JPN":"でもこの戦闘服、昔を思い出す。","ENG":"But this combat outfit does remind me of those days.","TWN":"但是這個戰鬥服倒是勾起了我的回憶。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"그때는 참 철이 없었지...... 후훗, 이렇게 했었나?","JPN":"あの頃は右も左もわからなかったな\\n……ふふっ、こうやってたっけ？","ENG":"I sure was so immature back then... Heh, did it go something like this?","TWN":"那時候我還真是不懂事……呵呵，是這樣做嗎？"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"필살, 이수연 스......","JPN":"必殺、カナミ・キズナス……","ENG":"Here comes a fatal blow, Lee Sooyeon Stri—","TWN":"必殺，李秀妍……"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"새 전술예장은 어떤가? 너무 끼거나 불편한 곳은 없나?","JPN":"新しい戦術礼装はどうだ？\\nきつくて動きにくい部位はなかったかね？","ENG":"So how do you like the new strategic uniform? It's not too tight or uncomfortable?","TWN":"新的戰術禮裝怎麼樣？會不會太緊，有沒有不合身的地方？"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"으아악! 노, 놀랐잖아요?!","JPN":"うわあっ！　お、驚かさないでくださいよ！","ENG":"Eeek! Y-you scared me!","TWN":"啊啊啊！我、我這不是被你嚇到了嗎？！"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"노크도 없이 통신을 걸다니 예, 예의가 없군요!","JPN":"ノックもなしに通信を始めるなんて、配慮に欠けます！","ENG":"You didn't even knock! How rude!","TWN":"你是不敲門就通信的嗎，太沒禮貌了！"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"통신 거는데 무슨 노크를 하나. 이상한 소릴 하는군.","JPN":"通信を始めるのにノックをしろって？\\n変なこと言うなよ。","ENG":"Who knocks during remote communication? Don't be silly.","TWN":"通信還敲什麼門，這什麼奇怪的話啊。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"제, 제가 그렇다면 그런 겁니다!","JPN":"た、たとえばの話です！","ENG":"W-whatever! If I say so, just knock!","TWN":"我、我說敲就要敲！"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"아무튼...... 제법 쓸만하긴 하네요.","JPN":"と…とにかく、そこそこ使えますね。","ENG":"Anyway... It's not bad.","TWN":"不過……確實很好用。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}}]`);export{e as default};